const body = $input.first().json.body;
if (body.event !== 'purchase.completed') return [];

const d = body.data;
return [{
  json: {
    date: new Date(body.timestamp).toISOString().split('T')[0],
    time: new Date(body.timestamp).toISOString().split('T')[1].split('.')[0],
    email: d.customer.email,
    name: [d.customer.firstName, d.customer.lastName].filter(Boolean).join(' ') || '-',
    product: d.product.name,
    product_id: d.product.id,
    amount: d.order.amount / 100,
    currency: d.order.currency.toUpperCase(),
    bump: d.bumpProduct?.name || '-',
    coupon: d.order.couponId || '-',
    guest: d.order.isGuest ? 'Yes' : 'No',
    stripe_session: d.order.sessionId,
    payment_intent: d.order.paymentIntentId
  }
}];
